package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines_defaultTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withIgnoreEmptyLines();
        assertNotNull(result);
        assertTrue(result.getIgnoreEmptyLines());
    }

    @Test
    public void testWithIgnoreEmptyLines_falseThenTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
        CSVFormat result = format.withIgnoreEmptyLines();
        assertTrue(result.getIgnoreEmptyLines());
    }

    @Test
    public void testWithIgnoreEmptyLines_idempotent() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        CSVFormat result = format.withIgnoreEmptyLines();
        assertSame(format, result);
    }
}
